import { useRef } from 'react';

type EqualityFn<T = unknown> = (a: T, b: T) => boolean;

/**
 * Returns the previous value of the passed value.
 * Whether the value has changed is determined by the equalityFn function. By default, strict equality is used.
 */
export function usePrevious<T>(
  value: T,
  initialValue?: T,
  equalityFn: NoInfer<EqualityFn<T>> = Object.is
): T | undefined {
  const { current } = useRef<{ prev: T | undefined; cur: T }>({ prev: initialValue, cur: value });

  if (!equalityFn(current.cur, value)) {
    current.prev = current.cur;
    current.cur = value;
  }

  return current.prev;
}
